import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  where,
  limit,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { Task, UserData, DBItem, MapSector, PartRequest, BOMRequest, BreakSchedule, SystemBreak, Role, Permission, Notification, PriorityLevel } from '../types/appTypes';
import { PRIORITY_ORDER } from '../constants/uiConstants';

export const useFirestoreData = (isAuthenticated: boolean, currentUserRole: string) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [users, setUsers] = useState<UserData[]>([]);
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, any>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); 
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = useCallback((permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  }, []);

  const checkBreakStatus = useCallback(() => {
      const now = new Date();
      const currentHHMM = now.getHours().toString().padStart(2, '0') + ':' + 
                          now.getMinutes().toString().padStart(2, '0');
      const isScheduledActive = (breakSchedules || []).some(b => 
          currentHHMM >= b.startTime && currentHHMM <= b.endTime
      );
      const isManualActive = (systemBreaks || []).some(b => b.isActive);
      setIsBreakActive(isScheduledActive || isManualActive);
  }, [breakSchedules, systemBreaks]);

  useEffect(() => {
      checkBreakStatus(); 
      const interval = setInterval(checkBreakStatus, 30000); 
      return () => clearInterval(interval);
  }, [checkBreakStatus]);

  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'];
        const pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated, checkPermissionRef]);

  useEffect(() => { 
      const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
      const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
      const unsubPerms = onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission))));
      const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubReasons = onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))));
      const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
          const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
          setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
      });
      const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
      const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));
      const unsubSysBreaks = onSnapshot(collection(db, 'system_breaks'), s => setSystemBreaks(s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak))));

      const unsubNotifications = onSnapshot(collection(db, 'notifications'), s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification))));

      return () => { 
        unsubUsers(); unsubRoles(); unsubPerms(); unsubWp(); unsubReasons(); 
        unsubSectors(); unsubLogOps(); unsubPartReq(); unsubBomReq(); unsubSysBreaks();
        unsubNotifications();
      };
  }, []);

  useEffect(() => {
    // REFACTORED: Parts Listener (Single Doc)
    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    // REFACTORED: BOM Listener (Single Doc)
    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, any[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubBreaks = onSnapshot(doc(db, 'settings', 'breaks'), (s) => {
      if (s.exists()) setBreakSchedules(s.data().data || []);
    });
    return () => { unsubParts(); unsubBOM(); unsubBreaks(); };
  }, []);

  // --- WRITE OPERATIONS ---

  const onAddTask = async (
    partNumber: string,
    workplace: string | null,
    quantity: string | null,
    quantityUnit: string | null,
    priority: PriorityLevel,
    isLogistics: boolean = false,
    note: string = '',
    isProduction: boolean = false
  ) => {
    const createdBy = localStorage.getItem('app_user') || 'Unknown';
    const newTask = {
        text: partNumber, 
        partNumber,
        workplace: workplace || '',
        quantity: quantity || '0',
        quantityUnit: quantityUnit || 'pcs',
        priority,
        isLogistics,
        isProduction,
        note,
        isDone: false,
        isMissing: false,
        createdAt: Date.now(),
        createdBy,
        status: 'open'
    };

    try {
        await addDoc(collection(db, 'tasks'), newTask);
    } catch (e) {
        console.error("Error adding task", e);
    }
  };

  const onUpdateTask = async (id: string, updates: Partial<Task>) => {
    try {
        const docRef = doc(db, 'tasks', id);
        await updateDoc(docRef, updates);
    } catch(e) {
        console.error("Error updating task", e);
    }
  };

  const onDeleteTask = async (id: string) => {
    try {
        await deleteDoc(doc(db, 'tasks', id));
    } catch(e) { console.error(e); }
  };

  const onToggleTask = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if(!task) return;
    const currentUser = localStorage.getItem('app_user') || 'Unknown';

    const updates: any = {
        isDone: !task.isDone
    };

    if (!task.isDone) {
        updates.completedAt = Date.now();
        updates.completedBy = currentUser;
        updates.status = 'completed';
    } else {
        updates.completedAt = null;
        updates.completedBy = null;
        updates.status = 'open';
    }

    await onUpdateTask(id, updates);
  };

  const onEditTask = async (id: string, newText: string, newPriority?: PriorityLevel) => {
    const updates: any = { text: newText, partNumber: newText };
    if (newPriority) updates.priority = newPriority;
    await onUpdateTask(id, updates);
  };

  const onToggleMissing = async (id: string, reason?: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';

    const updates: any = { isMissing: !task.isMissing };
    if (!task.isMissing) {
        updates.missingReason = reason || 'Unknown';
        updates.missingReportedBy = user;
    } else {
        updates.missingReason = null;
        updates.missingReportedBy = null;
    }
    await onUpdateTask(id, updates);
  };

  const onSetInProgress = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';

    if (task.isInProgress) {
        await onUpdateTask(id, { isInProgress: false, inProgressBy: null });
    } else {
        await onUpdateTask(id, { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
    }
  };

  const onToggleBlock = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';

    if (task.isBlocked) {
        await onUpdateTask(id, { isBlocked: false, blockedBy: null });
    } else {
        await onUpdateTask(id, { isBlocked: true, blockedBy: user });
    }
  };

  const onToggleManualBlock = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    await onUpdateTask(id, { isManualBlocked: !task.isManualBlocked });
  };

  const onExhaustSearch = async (id: string) => {
    await onUpdateTask(id, { searchExhausted: true });
  };

  const onMarkAsIncorrect = async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    await onUpdateTask(id, { 
        status: 'incorrectly_entered', 
        isDone: true, 
        completedBy: user, 
        completedAt: Date.now() 
    });
  };

  const onAddNote = async (id: string, note: string) => {
    await onUpdateTask(id, { note });
  };

  const onReleaseTask = async (id: string) => {
    await onUpdateTask(id, { 
        isBlocked: false, 
        isManualBlocked: false, 
        isInProgress: false, 
        inProgressBy: null,
        blockedBy: null
    });
  };

  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), {
            partNumber: part,
            requestedBy: user,
            requestedAt: Date.now()
        });
        return true;
    } catch (e) {
        return false;
    }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), {
            parentPart: parent,
            requestedBy: user,
            requestedAt: Date.now()
        });
        return true;
    } catch (e) {
        return false;
    }
  };

  const onAddNotification = async (notification: Partial<Notification>) => {
    try {
        await addDoc(collection(db, 'notifications'), {
            ...notification,
            timestamp: Date.now()
        });
    } catch (e) {
        console.error("Error adding notification", e);
    }
  };

  const onClearNotification = async (id: string) => {
    try {
        await deleteDoc(doc(db, 'notifications', id));
    } catch (e) {
        console.error("Error clearing notification", e);
    }
  };

  // --- SETTINGS CRUD OPERATIONS (REFACTORED FOR SINGLE DOC) ---

  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = {
              id: `part_${Date.now()}_${Math.random().toString(36).substr(2,9)}`,
              value: value.toUpperCase(),
              description,
              createdAt: Date.now()
          };
          await setDoc(doc(db, 'settings', 'parts'), {
              items: arrayUnion(newItem)
          }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) {
            itemsToAdd.push({
                id: `part_${Date.now()}_${Math.random().toString(36).substr(2,9)}_${itemsToAdd.length}`,
                value: p.trim().toUpperCase(),
                description: d ? d.trim() : '',
                createdAt: Date.now()
            });
        }
      });

      if (itemsToAdd.length > 0) {
          await setDoc(doc(db, 'settings', 'parts'), {
              items: arrayUnion(...itemsToAdd)
          }, { merge: true });
      }
    } catch (error) {
      console.error("Error batch adding parts:", error);
      throw error;
    }
  };

  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              // Filter out the item (matching by value since ID is internal)
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };

  const onDeleteAllParts = async () => {
      try {
          await setDoc(doc(db, 'settings', 'parts'), { items: [] });
          console.log("All parts cleared.");
      } catch (e) { console.error("Error clearing parts:", e); }
  };

  // Workplaces - Still using Collection based on requirement constraint to ONLY refactor Parts/BOM
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Missing Reasons
  const onAddMissingReason = async (val: string) => {
      await addDoc(collection(db, 'missing_reasons'), { value: val });
  };
  const onDeleteMissingReason = async (id: string) => {
      await deleteDoc(doc(db, 'missing_reasons', id));
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0) => {
      await addDoc(collection(db, 'logistics_operations'), { value: val, standardTime: time, distancePx: dist });
  };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'logistics_operations', id), updates);
  };
  const onDeleteLogisticsOperation = async (id: string) => {
      await deleteDoc(doc(db, 'logistics_operations', id));
  };

  // Users & Roles (Stubbed basic ops)
  const onAddUser = async (user: UserData) => {
      await addDoc(collection(db, 'users'), user);
  };
  const onUpdatePassword = async (username: string, newPass: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { password: newPass }));
  };
  const onUpdateNickname = async (username: string, newNick: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { nickname: newNick }));
  };
  const onUpdateUserRole = async (username: string, newRole: any) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { role: newRole }));
  };
  const onUpdateExportPermission = async (username: string, canExport: boolean) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { canExportAnalytics: canExport }));
  };
  const onDeleteUser = async (username: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => deleteDoc(d.ref));
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => {
      await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color });
  };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => {
      await updateDoc(doc(db, 'map_sectors', id), updates);
  };
  const onDeleteMapSector = async (id: string) => {
      await deleteDoc(doc(db, 'map_sectors', id));
  };

  // --- BOM (Kusovníky) CRUD Functions (REFACTORED FOR SINGLE DOC) ---

  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = {
              id: `bom_${Date.now()}_${Math.random().toString(36).substr(2,9)}`,
              parent: parent.toUpperCase(),
              child: child.toUpperCase(),
              consumption: qty,
              createdAt: Date.now()
          };
          await setDoc(doc(db, 'settings', 'bom'), {
              items: arrayUnion(newItem)
          }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) {
                  itemsToAdd.push({
                      id: `bom_${Date.now()}_${Math.random().toString(36).substr(2,9)}_${itemsToAdd.length}`,
                      parent: p.trim().toUpperCase(),
                      child: c.trim().toUpperCase(),
                      consumption: parseFloat(q?.replace(',', '.') || '0'),
                      createdAt: Date.now()
                  });
              }
          });

          if (itemsToAdd.length > 0) {
              await setDoc(doc(db, 'settings', 'bom'), {
                  items: arrayUnion(...itemsToAdd)
              }, { merge: true });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteAllBOMItems = async () => {
      try {
          await setDoc(doc(db, 'settings', 'bom'), { items: [] });
      } catch (e) { console.error(e); }
  };

  return {
    tasks, users, partsMap, bomMap, workplaces, missingReasons, logisticsOperations,
    mapSectors, partRequests, bomRequests, breakSchedules, systemBreaks, isBreakActive,
    roles, permissions, notifications, onClearNotification,
    // Task CRUD
    onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onEditTask, onToggleMissing,
    onSetInProgress, onToggleBlock, onToggleManualBlock, onExhaustSearch, 
    onMarkAsIncorrect, onAddNote, onReleaseTask, onRequestPart, onRequestBOM,
    onAddNotification,
    // Settings CRUD - Parts
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    // Settings CRUD - Workplaces
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    // Settings CRUD - Reasons & Ops
    onAddMissingReason, onDeleteMissingReason,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation,
    // Settings CRUD - Map Sectors
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    // Settings CRUD - Users
    onAddUser, onUpdatePassword, onUpdateNickname, onUpdateUserRole, onUpdateExportPermission, onDeleteUser,
    // Settings CRUD - BOM
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems
  };
};

import React, { useMemo, useState, useEffect } from 'react';
import { db } from '../../../firebase';
import { doc, getDoc } from 'firebase/firestore';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, UserData } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';
import AnalyticsExportPanel from './AnalyticsExportPanel';
import HighRunnerSection from './HighRunnerSection';
import HourlyChartSection from './HourlyChartSection';
import QualityAuditSection from './QualityAuditSection';
import WorkerDetailModal from './WorkerDetailModal';
import DrivingMetrics from './DrivingMetrics';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Cell } from 'recharts';

interface AnalyticsTabProps {
  tasks: Task[];
  onFetchArchivedTasks: () => Promise<Task[]>;
  systemBreaks: SystemBreak[];
  resolveName: (username?: string | null) => string;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
  logisticsOperations: DBItem[];
  users: UserData[];
  currentUser: string;
  currentUserRole: string;
  hasPermission: (permName: string) => boolean;
}

type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
type SourceFilter = 'ALL' | 'PROD' | 'LOG';
type ShiftFilter = 'ALL' | 'DAY' | 'NIGHT';

const AnalyticsTab: React.FC<AnalyticsTabProps> = ({ 
  tasks: _liveTasks, systemBreaks, resolveName, mapSectors, workplaces, systemConfig, logisticsOperations,
  users, currentUser, currentUserRole 
}) => {
  const [filterMode, setFilterMode] = useState<FilterMode>('TODAY');
  const [sourceFilter, setSourceFilter] = useState<SourceFilter>('ALL');
  const [shiftFilter, setShiftFilter] = useState<ShiftFilter>('ALL');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [archivedTasks, setArchivedTasks] = useState<Task[]>([]);
  const [selectedWorkerData, setSelectedWorkerData] = useState<{ name: string; tasks: Task[] } | null>(null);
  const { t, language } = useLanguage();

  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];

  const canExport = useMemo(() => {
    return currentUserRole === 'ADMIN' || (users?.find(u => u.username === currentUser)?.canExportAnalytics === true);
  }, [currentUser, currentUserRole, users]);

  useEffect(() => {
    const load = async () => {
      const results: Task[] = [];
      try {
          const draftSnap = await getDoc(doc(db, 'settings', 'draft'));
          if (draftSnap.exists()) {
              results.push(...(draftSnap.data().data || []));
          }
      } catch (err) {
          console.error("Failed to load draft tasks", err);
      }
      setArchivedTasks(results);
    };
    load();
  }, [filterMode, customStart, customEnd]);

  const filteredTasks = useMemo(() => {
    const combined = [..._liveTasks, ...archivedTasks];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayTs = today.getTime();

    return combined.filter(task => {
        const referenceTime = task.completedAt || task.createdAt || 0;
        if (!referenceTime) return false;

        let timeMatch = false;
        switch (filterMode) {
            case 'TODAY':
                timeMatch = referenceTime >= todayTs;
                break;
            case 'YESTERDAY':
                const yesterdayTs = todayTs - 86400000;
                timeMatch = referenceTime >= yesterdayTs && referenceTime < todayTs;
                break;
            case 'WEEK':
                const weekTs = todayTs - (today.getDay() || 7 - 1) * 86400000;
                timeMatch = referenceTime >= weekTs;
                break;
            case 'MONTH':
                const monthStart = new Date(today.getFullYear(), today.getMonth(), 1).getTime();
                timeMatch = referenceTime >= monthStart;
                break;
            case 'CUSTOM':
                if (!customStart || !customEnd) return false;
                const startTs = new Date(customStart).getTime();
                const endTs = new Date(customEnd).getTime() + 86399999;
                timeMatch = referenceTime >= startTs && referenceTime <= endTs;
                break;
            default:
                timeMatch = true;
        }
        if (!timeMatch) return false;

        if (sourceFilter === 'PROD' && !task.isProduction && task.isLogistics) return false;
        if (sourceFilter === 'LOG' && !task.isLogistics) return false;

        if (shiftFilter !== 'ALL') {
            const hour = new Date(referenceTime).getHours();
            const isDay = hour >= 6 && hour < 18;
            if (shiftFilter === 'DAY' && !isDay) return false;
            if (shiftFilter === 'NIGHT' && isDay) return false;
        }

        return true;
    });
  }, [_liveTasks, archivedTasks, filterMode, customStart, customEnd, sourceFilter, shiftFilter]);

  const stats = useMemo(() => {
    // Basic Counters
    let total = filteredTasks.length;
    let done = 0;

    // Aggregation Containers
    const workerMap: Record<string, Task[]> = {};
    const workplaceMap: Record<string, {load: number, pal: number, req: number}> = {};
    const partMap: Record<string, {load: number, pal: number, req: number}> = {};
    const hourlyMap: Record<number, {prod: number, log: number}> = {};

    // Quality & Driving
    let realErrorsCount = 0;
    let falseAlarmsCount = 0;
    let totalAuditedMissing = 0;
    const missingPartsMap: Record<string, number> = {};
    let totalFullDist = 0;
    let totalEmptyDist = 0;
    let totalRides = 0;

    filteredTasks.forEach(task => {
        // Status Counts
        if (task.isDone) done++;

        // Worker Stats
        if (task.isDone && task.completedBy) {
            if (!workerMap[task.completedBy]) workerMap[task.completedBy] = [];
            workerMap[task.completedBy].push(task);
        }

        // Quality
        if (task.auditResult) {
            totalAuditedMissing++;
            if (task.auditResult === 'NOK') realErrorsCount++;
            else if (task.auditResult === 'OK') falseAlarmsCount++;
        }
        if (task.isMissing && task.partNumber) {
            missingPartsMap[task.partNumber] = (missingPartsMap[task.partNumber] || 0) + 1;
        }

        // Hourly Data
        const time = task.completedAt || task.createdAt || 0;
        const hour = new Date(time).getHours();
        if (!hourlyMap[hour]) hourlyMap[hour] = { prod: 0, log: 0 };
        const load = (task.quantityUnit === 'pallet' ? parseFloat(task.quantity || '0') : 1) || 1;
        if (task.isLogistics) hourlyMap[hour].log += load;
        else hourlyMap[hour].prod += load;

        // High Runners & Workplaces
        if (task.isDone) {
            const qtyVal = parseFloat((task.quantity || '0').replace(',', '.'));
            const isPal = task.quantityUnit === 'pallet';
            const points = isPal ? qtyVal : 1;

            if (task.workplace) {
                if (!workplaceMap[task.workplace]) workplaceMap[task.workplace] = { load: 0, pal: 0, req: 0 };
                workplaceMap[task.workplace].load += points;
                workplaceMap[task.workplace].req++;
                if (isPal) workplaceMap[task.workplace].pal += qtyVal;
            }
            if (task.partNumber) {
                if (!partMap[task.partNumber]) partMap[task.partNumber] = { load: 0, pal: 0, req: 0 };
                partMap[task.partNumber].load += points;
                partMap[task.partNumber].req++;
                if (isPal) partMap[task.partNumber].pal += qtyVal;
            }
        }
    });

    // Transform Worker Stats
    const workerStats = Object.entries(workerMap).map(([uid, tasks]) => ({
        id: uid,
        name: resolveName(uid),
        count: tasks.length,
        tasks: tasks
    })).sort((a,b) => b.count - a.count);

    // Transform Hourly Data
    const hourlyData = Object.entries(hourlyMap).map(([h, d]) => ({
        hour: parseInt(h),
        label: `${h}:00`,
        production: d.prod,
        logistics: d.log
    })).sort((a,b) => a.hour - b.hour);

    // Transform High Runners
    const topWorkplaces = Object.entries(workplaceMap)
        .map(([k, v]) => ({ workplace: k, load: v.load, pal: v.pal, taskRequests: v.req, totalTasks: v.req }))
        .sort((a,b) => b.load - a.load).slice(0, 3);

    const topHighRunners = Object.entries(partMap)
        .map(([k, v]) => ({ partNumber: k, load: v.load, pal: v.pal, taskRequests: v.req, totalTasks: v.req }))
        .sort((a,b) => b.load - a.load).slice(0, 3);

    // Transform Missing Parts
    const topMissingParts = Object.entries(missingPartsMap)
        .map(([p, c]) => ({ partNumber: p, count: c }))
        .sort((a,b) => b.count - a.count).slice(0, 3);

    return { 
        total, 
        done, 
        efficiency: 0, 
        totalVolume: 0, 
        grandTotalExecutionTime: 0, 
        workerStats, 
        topHighRunners, 
        topWorkplaces, 
        hourlyData, 
        quality: { realErrorsCount, falseAlarmsCount, totalAuditedMissing, topMissingParts }, 
        driving: { totalFullDist, totalEmptyDist, totalRides, logEfficiency: 50 } 
    };
  }, [filteredTasks, resolveName]);

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
      <h1 className="text-2xl sm:text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('analytics_title')}</h1>

      <AnalyticsExportPanel 
        canExport={canExport} 
        tasks={filteredTasks} 
        systemBreaks={systemBreaks} 
        resolveName={resolveName} 
        t={t} 
        language={language} 
      />

      <div className="bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl overflow-hidden mb-8 flex flex-col">
        <button 
          onClick={() => setIsFilterOpen(!isFilterOpen)} 
          className="w-full flex items-center justify-between p-6 bg-slate-800/40 hover:bg-slate-800/60 transition-colors border-b border-slate-800/50"
        >
          <div className="flex items-center gap-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-teal-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
            </svg>
            <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">FILTRÁCIA DÁT</h3>
          </div>
          <div className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" />
            </svg>
          </div>
        </button>

        {isFilterOpen && (
          <div className="p-8 space-y-8 animate-fade-in">
            <div>
              <label className="block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">Časový Rozsah</label>
              <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
                {(['TODAY', 'YESTERDAY', 'WEEK', 'MONTH', 'CUSTOM'] as FilterMode[]).map(m => (
                  <button 
                    key={m} 
                    onClick={() => setFilterMode(m)} 
                    className={`h-11 px-4 rounded-xl text-[10px] font-black uppercase transition-all border-2 ${
                      filterMode === m ? 'bg-amber-500/10 border-amber-500 text-amber-500 shadow-lg shadow-amber-500/10' : 'bg-slate-800/50 border-slate-800 text-slate-500 hover:text-slate-300'
                    }`}
                  >
                    {t(`filter_${m.toLowerCase()}` as any)}
                  </button>
                ))}
              </div>

              {filterMode === 'CUSTOM' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4 animate-fade-in">
                  <div className="space-y-1.5">
                    <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Od</span>
                    <input 
                      type="date" 
                      min={firstDayOfMonth} 
                      max={lastDayOfMonth} 
                      value={customStart} 
                      onChange={e => setCustomStart(e.target.value)} 
                      className="w-full h-12 bg-slate-950 border-2 border-slate-800 rounded-xl px-4 text-white text-sm focus:border-amber-500 transition-all outline-none" 
                    />
                  </div>
                  <div className="space-y-1.5">
                    <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest ml-1">Do</span>
                    <input 
                      type="date" 
                      min={firstDayOfMonth} 
                      max={lastDayOfMonth} 
                      value={customEnd} 
                      onChange={e => setCustomEnd(e.target.value)} 
                      className="w-full h-12 bg-slate-950 border-2 border-slate-800 rounded-xl px-4 text-white text-sm focus:border-amber-500 transition-all outline-none" 
                    />
                  </div>
                </div>
              )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-4 border-t border-slate-800/50">
              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">Zdroj Dát</label>
                <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800">
                  {(['ALL', 'PROD', 'LOG'] as SourceFilter[]).map(s => (
                    <button 
                      key={s} 
                      onClick={() => setSourceFilter(s)} 
                      className={`flex-1 h-10 rounded-lg text-[10px] font-black uppercase transition-all ${
                        sourceFilter === s ? 'bg-teal-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'
                      }`}
                    >
                      {s === 'ALL' ? 'Všetko' : s === 'PROD' ? 'Výroba' : 'Logistika'}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">Smena</label>
                <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800">
                  {(['ALL', 'DAY', 'NIGHT'] as ShiftFilter[]).map(sh => (
                    <button 
                      key={sh} 
                      onClick={() => setShiftFilter(sh)} 
                      className={`flex-1 h-10 rounded-lg text-[10px] font-black uppercase transition-all ${
                        shiftFilter === sh ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-300'
                      }`}
                    >
                      {sh === 'ALL' ? 'Všetky' : sh === 'DAY' ? 'Denná' : 'Nočná'}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-5">
        <div className="bg-slate-900/60 p-5 rounded-2xl border border-slate-800 border-l-4 border-l-blue-500 shadow-xl">
          <p className="text-slate-500 text-[10px] font-black uppercase">{t('kpi_total')}</p>
          <p className="text-3xl font-black text-white mt-2 font-mono">{stats.total}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl border border-slate-800 border-l-4 border-l-green-500 shadow-xl">
          <p className="text-slate-500 text-[10px] font-black uppercase">{language === 'sk' ? 'DOKONČENÉ' : 'COMPLETED'}</p>
          <p className="text-3xl font-black text-white mt-2 font-mono">{stats.done}</p>
        </div>
      </div>

      <QualityAuditSection data={stats.quality} t={t} />
      <HighRunnerSection topHighRunners={stats.topHighRunners} topWorkplaces={stats.topWorkplaces} t={t} />
      <HourlyChartSection hourlyData={stats.hourlyData} t={t} />

      {/* WORKER PERFORMANCE CHART */}
      <div className="bg-slate-900 border border-slate-800 p-6 rounded-3xl shadow-2xl overflow-hidden">
          <div className="flex items-center gap-3 mb-6 border-b border-white/5 pb-6">
              <div className="w-1.5 h-6 bg-purple-500 rounded-full"></div>
              <h3 className="text-sm font-black text-white uppercase tracking-[0.25em]">{language === 'sk' ? 'VÝKONNOSŤ SKLADNÍKOV' : 'WORKER PERFORMANCE'}</h3>
          </div>
          <div className="h-[400px] w-full">
              {stats.workerStats.length > 0 ? (
                  <ResponsiveContainer width="100%" height="100%">
                      <BarChart data={stats.workerStats} layout="vertical" margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                          <CartesianGrid strokeDasharray="3 3" stroke="#334155" horizontal={false} />
                          <XAxis type="number" stroke="#94a3b8" fontSize={10} fontWeight="bold" />
                          <YAxis dataKey="name" type="category" stroke="#fff" fontSize={11} fontWeight="bold" width={100} />
                          <Tooltip 
                              cursor={{ fill: '#334155', opacity: 0.4 }}
                              contentStyle={{ backgroundColor: '#0f172a', borderColor: '#1e293b', borderRadius: '12px', color: '#fff' }}
                              itemStyle={{ color: '#818cf8', fontWeight: 'bold' }}
                          />
                          <Bar 
                              dataKey="count" 
                              fill="#8b5cf6" 
                              radius={[0, 4, 4, 0]} 
                              barSize={20} 
                              onClick={(entry: any) => setSelectedWorkerData({ name: entry.name, tasks: entry.tasks })} 
                              cursor="pointer"
                          >
                              {stats.workerStats.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={index < 3 ? '#a78bfa' : '#6d28d9'} />
                              ))}
                          </Bar>
                      </BarChart>
                  </ResponsiveContainer>
              ) : (
                  <div className="flex h-full items-center justify-center">
                      <p className="text-slate-600 font-bold uppercase tracking-widest text-xs">{t('no_data')}</p>
                  </div>
              )}
          </div>
      </div>

      <DrivingMetrics totalKm={stats.driving.totalFullDist} emptyKm={stats.driving.totalEmptyDist} rides={stats.driving.totalRides} efficiency={stats.driving.logEfficiency} vzvSpeed={systemConfig.vzvSpeed || 8} />

      {selectedWorkerData && (
        <WorkerDetailModal 
          name={selectedWorkerData.name} 
          tasks={selectedWorkerData.tasks} 
          periodLabel={filterMode} 
          systemBreaks={systemBreaks} 
          onClose={() => setSelectedWorkerData(null)} 
          mapSectors={mapSectors} 
          workplaces={workplaces} 
          systemConfig={systemConfig} 
          logisticsOperations={logisticsOperations} 
        />
      )}
    </div>
  );
};

export default AnalyticsTab;
